const webhookItem = $('Webhook').first();
const webhookData = webhookItem.json.body || {};
const rawHistory = $input.all().map(i => i.json);
const chatHistory = rawHistory.filter(msg => msg && msg.role && msg.content).reverse();
const webhookBinary = webhookItem.binary;
const imageBase64 = (webhookBinary && webhookBinary.image && webhookBinary.image.data) ? webhookBinary.image.data : null;
return [{ json: {
  query: webhookData.query || "",
  base: webhookData.base || "privada",
  user_name: webhookData.userName || webhookData.user_name || "Usuario",
  user_email: webhookData.userEmail || webhookData.user_email || "no-email@satcomla.com",
  session_id: webhookData.sessionId || webhookData.session_id || "unknown",
  image_base64: imageBase64,
  chat_history: chatHistory
} }];
